head.script:
scwin.g_sUserId = "";
scwin.vAuthYn = "N";
//---------------------------------------------------------
// 전역변수
//---------------------------------------------------------   
scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "ZZ006", compID: "lc_crcCd" }
    ];
    $c.data.setCommonCode(codeOptions, scwin.setInit);
    $c.gus.cfDisableObjects([ed_closeYm, txt_closeYn, ed_magamDt, btn_includeSave]);
    let memJson = $c.data.getMemInfo();
    console.log("### onpageload :: " + JSON.stringify(memJson));
    scwin.g_sUserId = memJson.empNo;

    scwin.f_retrieveAuth();
};

//---------------------------------------------------------
// UDC
//---------------------------------------------------------    
scwin.onUdcCompleted = function () {
    today = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    ed_stdYm.setValue(today.substr(0, 6));
}

//---------------------------------------------------------
// 사용자 함수
//---------------------------------------------------------   
scwin.setInit = function () {
    lc_crcCd.addItem("전체", "", null, 0);
    lc_crcCd.setValue("USD");
    ds_comCode.setJSON(dlt_commonCodeZZ006.getAllJSON());
}

scwin.f_retrieveAuth = function () {
    sbm_auth.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=retrieveBorrowAcqKindInfo&param1=IL110" + "&param2=" + scwin.g_sUserId;
    $c.sbm.execute(sbm_auth);
}

scwin.f_getMagam = function () {
    var vStdYm = ed_stdYm.getValue();

    // SELECT 절 
    var param1 =
        " TO_CHAR(MAX(A.REG_DTM),'YYYYMMDD')  as COL1 "
        + ",''      as COL2 "
        + ",''      as COL3 "
        + ",'' 		as COL4 "
        + ",'' 		as COL5 "
        + ",'' 		as COL6 "
        + ",''      as COL7 "
        + ",''      as COL8 "
        + ",''      as COL9 "
        + ",''      as COL10"
        ;

    // 대상테이블 	
    var param2 = " TB_ZZ420 A, TB_ZZ419 B";

    // 조건절
    var param3 =
        " AND A.CLOSE_YM = '" + vStdYm + "'"
        + " AND A.WRK_NO = 'IL01' "
        + " AND A.CLOSE_YM = B.CLOSE_YM "
        + " AND A.WRK_NO = B.WRK_NO "
        + " AND B.CLOSE_PRGS_STS_CD = '2' "
        ;
    sbm_magam.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=A.REG_DTM";
    $c.sbm.execute(sbm_magam);
}

scwin.getLastDayOfMonth = function () {
    yyyymm = ed_stdYm.getValue();
    if (!yyyymm || yyyymm.length !== 6) return "";

    var year = parseInt(yyyymm.substring(0, 4), 10);
    var month = parseInt(yyyymm.substring(4, 6), 10);

    // 다음 달 0일 = 현재 달 마지막 날
    var lastDt = new Date(year, month, 0).getDate();
    if (lastDt == '31') {
        gr_acctRecvList.setColumnVisible("amt29d", "true");
        gr_acctRecvList.setColumnVisible("amt30d", "true");
        gr_acctRecvList.setColumnVisible("amt31d", "true");
    } else if (lastDt == '30') {
        gr_acctRecvList.setColumnVisible("amt29d", "true");
        gr_acctRecvList.setColumnVisible("amt30d", "true");
        gr_acctRecvList.setColumnVisible("amt31d", "false");
    } else if (lastDt == '29') {
        gr_acctRecvList.setColumnVisible("amt29d", "true");
        gr_acctRecvList.setColumnVisible("amt30d", "false");
        gr_acctRecvList.setColumnVisible("amt31d", "false");
    } else if (lastDt == '28') {
        gr_acctRecvList.setColumnVisible("amt29d", "false");
        gr_acctRecvList.setColumnVisible("amt30d", "false");
        gr_acctRecvList.setColumnVisible("amt31d", "false");
    }
}

scwin.f_Retrieve = function () {

    if (ed_stdYm.getValue() == "") {
        $c.win.alert("기준년월은(는) 필수 입력 항목 입니다.");
        return;
    }

    $c.sbm.execute(sbm_retrieve);
}

scwin.f_add = function () {
    idx = ds_additionalValue.insertRow();
    ds_additionalValue.setCellData(idx, "crcCd", "USD");
    ds_additionalValue.setCellData(idx, "additionalKndCd", "1");
    ds_additionalValue.setCellData(idx, "amtFcrc", "0");
    gr_additionalValue.setFocusedCell(idx, 0);
    gr_additionalValue.setReadOnly("cell", idx, 0, false);
    gr_additionalValue.setReadOnly("cell", idx, 2, false);
    gr_additionalValue.setReadOnly("cell", idx, 4, false);
    gr_additionalValue.setReadOnly("cell", idx, 5, false);
}

scwin.f_delete = function () {
    row = gr_additionalValue.getFocusedRowIndex();
    if (ds_additionalValue.getRowStatus(row) == "C") {
        ds_additionalValue.removeRow(row);
        return;
    }
    if (ds_auth.getTotalRow() != 0 || ds_additionalValue.getCellData(gr_additionalValue.getFocusedRowIndex(), "regId") == scwin.g_sUserId || "" == ds_additionalValue.getCellData(gr_additionalValue.getFocusedRowIndex(), "regId")) {
        ds_additionalValue.modifyRowStatus(gr_additionalValue.getFocusedRowIndex(), "D");
    } else {
        $c.win.alert("작성자만 삭제할 수 있습니다.");
    }
}

scwin.f_cancel = function () {
    row = gr_additionalValue.getFocusedRowIndex();
    if (ds_additionalValue.getRowStatus(row) == "C") {
        ds_additionalValue.removeRow(row);
        return;
    }
    if (ds_additionalValue.getRowStatus() == "C") {
        ds_additionalValue.removeRow();
    } else {
        ds_additionalValue.undoRow(gr_additionalValue.getFocusedRowIndex());
    }
}

scwin.f_openPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
    // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
    // 넘어온 OBJ가 EMEdit인지 TextBox인지 구분한다.
    if (flag == "ALL") {
        cd = "";
        nm = "";
    } else {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
    }
    switch (select_code) {
        // 조회조건용 거래처 PopUp 호출
        case '1':

            break;
        case '2':
            param = "000";
            udc_clnt.setSelectId("retrieveClntEmpNoList");
            udc_clnt.cfCommonPopUp(scwin.udc_clnt_callbackFunc, cd, nm, "T", null, null, null, null, null, null, null, null, null); //사업자번호
            break;
        case '31':
            udc_user.setSelectId("retrieveAcEmpInfo");
            udc_user.cfCommonPopUp(scwin.udc_user_callbackFunc, cd, nm, "T", null, null, null, null, null, null, null, null, null); // 거래처
            break;
        case '32':
            udc_pic.setSelectId("retrieveAcEmpInfo");
            udc_pic.cfCommonPopUp(scwin.udc_pic_callbackFunc, cd, nm, "T", null, null, null, null, null, null, null, null, null); // 거래처
            break;
        case '33':
            udc_reg.setSelectId("retrieveAcEmpInfo");
            udc_reg.cfCommonPopUp(scwin.udc_reg_callbackFUnc, cd, nm, "T", null, null, null, null, null, null, null, null, null); // 거래처
            break;
    }
}

scwin.udc_clnt_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm);
}

scwin.udc_user_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_userId, ed_userNm);
}

scwin.udc_pic_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_picId, ed_picNm);
}

scwin.udc_reg_callbackFUnc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_regId, ed_regNm);
}

scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
    // if (flag == "CD") {
    //     if (orgObjCd.getValue() == orgObjCd.hidVal) {
    //         return;
    //     } else {
    //         orgObjNm.setValue("");
    //     }
    // } else {
    //     if (orgObjNm.Text == orgObjNm.hidVal) {
    //         return;
    //     } else {
    //         orgObjCd.Text = "";
    //     }
    // }

    if (orgObjCd.getValue() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue());
            orgObjNm.setValue(orgObjNm.getValue());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
    }
}

scwin.f_IncludeSave = function () {
    if (ds_acctRecvList.getTotalRow() == 0) {
        $c.win.alert("데이타가 없습니다.");
        return;
    }

    $c.sbm.execute(sbm_IncludeSave);
}

scwin.f_JobCloseYN = async function () {

    //cfJobCloseYN(마감요청구분,마감년월,마감일,작업번호,관리번호,리턴구분);
    var isClose = await udc_closeYn.cfJobCloseYN("CUR", ed_stdYm.getValue(), "00", "IL01", "0", "ARR", "", "000");

    ds_closeYm.set("closeYm", ed_stdYm.getValue());
    ds_closeYm.set("wrkNo", "IL01");
    ds_closeYm.set("crcCd", lc_crcCd.getValue());

    // 해당마감 작업에 대한 검사
    if (isClose[0] == "2") {
        txt_closeYn.setValue("확정");
        $c.gus.cfDisableObjects([btn_confirm, btn_addItem, btn_deleteItem, btn_cancelItem, btn_save, btn_includeSave]);

        if (scwin.vAuthYn == "Y") {
            $c.gus.cfEnableObjects([btn_cancelConfirm]);

        } else {
            $c.gus.cfDisableObjects([btn_cancelConfirm]);
        }
    } else {
        txt_closeYn.setValue("미확정");
        $c.gus.cfDisableObjects([btn_cancelConfirm]);
        $c.gus.cfEnableObjects([btn_addItem, btn_deleteItem, btn_cancelItem, btn_save]);

        if (scwin.vAuthYn == "Y") {
            $c.gus.cfEnableObjects([btn_confirm, btn_includeSave]);

        } else {
            $c.gus.cfDisableObjects([btn_confirm, btn_includeSave]);
        }
    }
}

scwin.f_CloseYmConfirm = function (param) {
    if (ed_closeYm.getValue() == "") {
        $c.win.alert("내역이 존재하지않습니다.");
        return false;
    }

    ds_closeYm.set("crcCd", lc_crcCd.getValue());

    if (param == "Y") {
        ds_closeYm.set("closeYn", "2"); //확정
    } else {
        ds_closeYm.set("closeYn", "1"); //확정취소
    }

    $c.sbm.execute(sbm_saveConfirmYn);
}

scwin.f_save = async function () {
    let validArray = [
        { id: "clntNo", name: "거래처번호", mandatory: true },
        { id: "stdDt", name: "요청일자", mandatory: true },
    ];
    ret = await $c.gus.cfValidateGrid(gr_additionalValue, null, null, validArray, "");
    if (!ret) return false;

    if (ds_additionalValue.getTotalRow() == 0) {
        $c.win.alert("데이타가 없습니다.");
        return;
    }

    if (ds_additionalValue.getModifiedJSON().length == 0) {
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    for (var i = 0; i < ds_additionalValue.getTotalRow(); i++) {
        var vStdDt = ds_additionalValue.getCellData(i, "stdDt").substring(0, 6);

        if (vStdDt != ed_stdYm.getValue()) {
            $c.win.alert((i + 1) + "행의 날짜는 기준년월의 월과 같아야 합니다.");
            return;
        }

    }

    $c.sbm.execute(sbm_save);
}

scwin.f_IncludeSave = function () {
    if (ds_acctRecvList.getTotalRow() == 0) {
        $c.win.alert("데이타가 없습니다.");
        return;
    }

    $c.sbm.execute(sbm_IncludeSave);
}

scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList;

    row = gr_additionalValue.getFocusedRowIndex();
    switch (disGubun) {
        case 1:

            break;

        case 2:

            param = ",,,000";

            pCode = ds_additionalValue.getCellData(row, "clntNo");


            //		rtnList = cfCommonPopUp('retrieveClntList','','',"T",null,null,null,"3,4,5,6,7,8,9,10",null,null,null,null,null,null,null,null); //  사업자등록번호
            udc_clnt.setSelectId("retrieveClntList");
            udc_clnt.cfCommonPopUp(scwin.udc_clnt2_callbackFunc, pCode, '', "T", null, null, null, "3,4,5,6,7,8,9,10", param, null, null, null, null, null, null, null); // 사업자등록번호
            break;
    }
}

scwin.udc_clnt2_callbackFunc = function (rtnList) {
    row = gr_additionalValue.getFocusedRowIndex();
    ds_additionalValue.setCellData(row, "clntNo", rtnList[0] || "");
    ds_additionalValue.setCellData(row, "clntNm", rtnList[1] || "");
}

scwin.f_GridToExcel = async function () {
    if (ds_acctRecvList.getRowCount() == 0) {
        await $c.win.alert("내역이 존재하지않습니다.");
        return;
    }

    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        await $c.data.downloadGridViewExcel(gr_acctRecvList, { fileName: "당월계획_수입" + ".xlsx", sheetName: "당월계획_수입" });
    }
}
//---------------------------------------------------------
// 컴포넌트 이벤트
//---------------------------------------------------------   
scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.udc_clnt_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_clntNo, ed_clntNm, '2', 'CD');
};

scwin.udc_clnt_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_clntNo, ed_clntNm, '2', 'NM');
};

scwin.udc_clnt_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_clntNo, ed_clntNm, '2', 'ALL');
};

scwin.udc_user_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_userId, ed_userNm, '31', 'CD');
};

scwin.udc_user_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_userId, ed_userNm, '31', 'NM');
};

scwin.udc_user_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_userId, ed_userNm, '31', 'ALL');
};

scwin.udc_pic_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_picId, ed_picNm, '32', 'CD');
};

scwin.udc_pic_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_picId, ed_picNm, '32', 'NM');
};

scwin.udc_pic_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_picId, ed_picNm, '32', 'ALL');
};

scwin.udc_reg_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_regId, ed_regNm, '33', 'CD');
};

scwin.udc_reg_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_regId, ed_regNm, '33', 'NM');
};

scwin.udc_reg_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_regId, ed_regNm, '33', 'ALL');
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if (ds_acctRecvList.getTotalRow() == 0) {
        await $c.win.alert("Data not found.");
    }
    scwin.f_JobCloseYN(); //마감체크  
    scwin.getLastDayOfMonth();
    gr_acctRecvList.setColumnReadOnly("includeYn", scwin.vAuthYn == "N" ? true : false);
    ed_totalRow.setValue(ds_acctRecvList.getRowCount());

    $c.sbm.execute(sbm_retrieveAdditionalValue);
}

scwin.sbm_retrieveAdditionalValue_submitdone = function (e) {
    // 거래 실패시 return 처리
    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    scwin.f_getMagam();
    ed_totalRow2.setValue(ds_additionalValue.getTotalRow());
}

scwin.btn_save_onclick = function (e) {
    scwin.f_save();
};

scwin.btn_includeSave_onclick = function (e) {
    scwin.f_IncludeSave();
};

scwin.btn_confirm_onclick = function (e) {
    scwin.f_CloseYmConfirm("Y");
};

scwin.btn_cancelConfirm_onclick = function (e) {
    scwin.f_CloseYmConfirm("N");
};

scwin.btn_retrieve2_onclick = function (e) {
    if (!$c.gus.cfValidate([ed_stdYm])) return false;
    $c.sbm.execute(sbm_retrieveAdditionalValue);
};

scwin.f_IncludeSave_onclick = function (e) {
    scwin.f_IncldudeSave = function () {
        if (ds_acctRecvList.getTotalRow == 0) {
            $c.win.alert("데이타가 없습니다.");
            return;
        }

        $c.sbm.execute(sbm_cludeSave);
    }
};

scwin.sbm_auth_submitdone = function (e) {
    ds_auth.setJSON(e.responseJSON.GAUCE);
    if (ds_auth.getTotalRow() != 0) {
        $c.gus.cfEnableObjects([btn_confirm, btn_cancelConfirm, btn_includeSave]);
        scwin.vAuthYn = "Y";
    } else {
        $c.gus.cfDisableObjects([btn_confirm, btn_cancelConfirm, btn_includeSave]);
        scwin.vAuthYn = "N";
    }
    scwin.f_JobCloseYN(); //마감체크  
    scwin.f_getMagam();
}

scwin.gr_additionalValue_ontextimageclick = function (rowIndex, columnIndex) {
    scwin.f_openCommonPopUp(2, '', '', 'T', 'T');
};

scwin.sbm_save_submitdone = async function (e) {
    // 거래 실패시 return 처리
    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    $c.sbm.execute(sbm_retrieveAdditionalValue);
}

scwin.sbm_IncludeSave_submitdone = async function (e) {
    // 거래 실패시 return 처리
    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    $c.sbm.execute(sbm_retrieve);
}

scwin.sbm_saveConfirmYn_submitdone = async function (e) {
    // 거래 실패시 return 처리
    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    await $c.win.alert("수입계획서 확정여부가 저장되었습니다.");
    scwin.f_JobCloseYN(); //마감체크  
    scwin.f_getMagam(); //확정일자
    $c.sbm.execute(sbm_retrieveAdditionalValue);
}
scwin.gr_additionalValue_onviewchange = function (info) {
    if (info.colId == "clntNo") {
        scwin.f_openCommonPopUp(2, '', '', 'T', 'T');   // 거래처
    } else if (info.colId == "summaryCombo") {
        let combo = ds_additionalValue.getCellData(info.rowIndex, "summaryCombo");

        switch (combo) {
            case "0":
                ds_additionalValue.setCellData(info.rowIndex, "summary", "");
                gr_additionalValue.setColumnReadOnly("summary", true);
                break;
            case "1":
                ds_additionalValue.setCellData(info.rowIndex, "summary", "포함 요청");
                gr_additionalValue.setColumnReadOnly("summary", true);
                break;
            case "2":
                ds_additionalValue.setCellData(info.rowIndex, "summary", "포함해제 요청");
                gr_additionalValue.setColumnReadOnly("summary", true);
                break;
            case "3":
                ds_additionalValue.setCellData(info.rowIndex, "summary", "");
                gr_additionalValue.setColumnReadOnly("summary", false);
                break;
        }
    }
};

scwin.f_Excel = function () {
    let options = {
        fileName: "추가값" + ".xlsx",
        sheetName: "추가값"
    }

    $c.data.downloadGridViewExcel(gr_additionalValue, options);
};

scwin.gr_additionalValue_oncellclick = function (rowIndex, columnIndex, columnId) {
    row = rowIndex;
    colid = columnId;
    if (txt_closeYn.getValue() == "확정") {
        gr_additionalValue.setCellReadOnly(row, "clntNo", true);
        gr_additionalValue.setCellReadOnly(row, "stdDt", true);
        gr_additionalValue.setCellReadOnly(row, "amtFcrc", true);
        gr_additionalValue.setCellReadOnly(row, "summary", true);
        gr_additionalValue.setCellReadOnly(row, "summaryCombo", true);
    } else {
        if (colid == "summary") {
            var combo = ds_additionalValue.getCellData(row, "summaryCombo");
            switch (combo) {
                case "0":
                    // 	 			ds_additionalValue.NameValue(row,"summary") = "";
                    gr_additionalValue.setCellReadOnly(row, "summary", true);
                    break;
                case "1":
                    // 				ds_additionalValue.NameValue(row,"summary") = "포함 요청";
                    gr_additionalValue.setCellReadOnly(row, "summary", true);
                    break;
                case "2":
                    // 				ds_additionalValue.NameValue(row,"summary") = "포함해제 요청";
                    gr_additionalValue.setCellReadOnly(row, "summary", true);
                    break;
                case "3":
                    // 				ds_additionalValue.NameValue(row,"summary") = "";
                    gr_additionalValue.setCellReadOnly(row, "summary", false);
                    break;
                default:
                    gr_additionalValue.setCellReadOnly(row, "summary", true);
                    break;
            }
        }
        if (ds_additionalValue.getRowStatus(row) == "C") {
            gr_additionalValue.setReadOnly("grid", false);
            gr_additionalValue.setCellReadOnly(row, "clntNo", false);
            gr_additionalValue.setCellReadOnly(row, "stdDt", false);
        } else {
            gr_additionalValue.setCellReadOnly(row, "clntNo", true);
            gr_additionalValue.setCellReadOnly(row, "stdDt", false);

            if (ds_auth.getTotalRow() != 0 || ds_additionalValue.getCellData(row, "regId") == scwin.g_sUserId) {
                gr_additionalValue.setReadOnly("grid", false);
                gr_additionalValue.setCellReadOnly(row, "amtFcrc", false);
                gr_additionalValue.setCellReadOnly(row, "stdDt", false);
                gr_additionalValue.setCellReadOnly(row, "summaryCombo", false);
            } else {
                gr_additionalValue.setReadOnly("grid", true);
                gr_additionalValue.setCellReadOnly(row, "amtFcrc", true);
                gr_additionalValue.setCellReadOnly(row, "stdDt", true);
                gr_additionalValue.setCellReadOnly(row, "summaryCombo", true);
            }
        }
    }
};

scwin.sbm_magam_submitdone = function(e) {
    ed_magamDt.setValue(e.responseJSON.GAUCE[0].col1);
}
